const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const crypto = require('crypto');

const app = express();

// Security headers
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'"],
      imgSrc: ["'self'"],
      connectSrc: ["'self'"],
      fontSrc: ["'self'"],
      objectSrc: ["'none'"],
      mediaSrc: ["'self'"],
      frameSrc: ["'none'"]
    }
  },
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  }
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: 'Too many requests from this IP',
  standardHeaders: true,
  legacyHeaders: false
});

app.use(limiter);

// API key validation middleware
const validateApiKey = (req, res, next) => {
  const apiKey = req.headers['x-api-key'];
  
  if (!apiKey) {
    return res.status(401).json({ error: 'API key required' });
  }
  
  // Retrieve API keys from environment variable (secure storage)
  const validApiKeys = process.env.VALID_API_KEYS ? process.env.VALID_API_KEYS.split(',') : [];
  
  // Constant-time comparison to prevent timing attacks
  let isValid = false;
  for (const validKey of validApiKeys) {
    if (validKey && crypto.timingSafeEqual(
      Buffer.from(apiKey),
      Buffer.from(validKey)
    )) {
      isValid = true;
      break;
    }
  }
  
  if (!isValid) {
    return res.status(403).json({ error: 'Invalid API key' });
  }
  
  next();
};

// CORS middleware with security controls
app.use((req, res, next) => {
  const allowedOrigins = process.env.ALLOWED_ORIGINS 
    ? process.env.ALLOWED_ORIGINS.split(',') 
    : ['*'];
  
  const origin = req.headers.origin;
  
  if (allowedOrigins.includes('*')) {
    res.setHeader('Access-Control-Allow-Origin', '*');
  } else if (origin && allowedOrigins.includes(origin)) {
    res.setHeader('Access-Control-Allow-Origin', origin);
    res.setHeader('Vary', 'Origin');
  }
  
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, PATCH, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization, X-API-Key, X-Request-ID');
  res.setHeader('Access-Control-Max-Age', '86400');
  res.setHeader('Access-Control-Allow-Credentials', 'false');
  
  if (req.method === 'OPTIONS') {
    return res.status(204).end();
  }
  
  next();
});

// Request parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Request ID for tracking
app.use((req, res, next) => {
  req.id = crypto.randomUUID();
  res.setHeader('X-Request-ID', req.id);
  next();
});

// Input validation helper
const validateInput = (input, type, maxLength = 1000) => {
  if (typeof input !== type) {
    return false;
  }
  
  if (type === 'string' && input.length > maxLength) {
    return false;
  }
  
  // Sanitize string inputs
  if (type === 'string') {
    const sanitized = input.replace(/[<>\"'&]/g, '');
    return sanitized;
  }
  
  return input;
};

// Apply API key validation to all routes except health check
app.get('/health', (req, res) => {
  res.status(200).json({ status: 'healthy', timestamp: new Date().toISOString() });
});

app.use('/api', validateApiKey);

// Example protected routes
app.get('/api/data', (req, res) => {
  const page = parseInt(req.query.page) || 1;
  const limit = Math.min(parseInt(req.query.limit) || 10, 100);
  
  if (page < 1 || limit < 1) {
    return res.status(400).json({ error: 'Invalid pagination parameters' });
  }
  
  res.json({
    data: [],
    page,
    limit,
    requestId: req.id
  });
});

app.post('/api/data', (req, res) => {
  const { name, value } = req.body;
  
  const validatedName = validateInput(name, 'string', 100);
  const validatedValue = validateInput(value, 'string', 500);
  
  if (!validatedName || !validatedValue) {
    return res.status(400).json({ error: 'Invalid input data' });
  }
  
  res.status(201).json({
    message: 'Data created',
    data: { name: validatedName, value: validatedValue },
    requestId: req.id
  });
});

app.put('/api/data/:id', (req, res) => {
  const id = validateInput(req.params.id, 'string', 50);
  
  if (!id || !/^[a-zA-Z0-9-_]+$/.test(id)) {
    return res.status(400).json({ error: 'Invalid ID format' });
  }
  
  const { name, value } = req.body;
  const validatedName = validateInput(name, 'string', 100);
  const validatedValue = validateInput(value, 'string', 500);
  
  if (!validatedName || !validatedValue) {
    return res.status(400).json({ error: 'Invalid input data' });
  }
  
  res.json({
    message: 'Data updated',
    id,
    data: { name: validatedName, value: validatedValue },
    requestId: req.id
  });
});

app.delete('/api/data/:id', (req, res) => {
  const id = validateInput(req.params.id, 'string', 50);
  
  if (!id || !/^[a-zA-Z0-9-_]+$/.test(id)) {
    return res.status(400).json({ error: 'Invalid ID format' });
  }
  
  res.json({
    message: 'Data deleted',
    id,
    requestId: req.id
  });
});

// Error handling
app.use((err, req, res, next) => {
  console.error(`Error [${req.id}]:`, err.message);
  
  res.status(err.status || 500).json({
    error: 'Internal server error',
    requestId: req.id
  });
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({
    error: 'Route not found',
    requestId: req.id
  });
});

const PORT = process.env.PORT || 3000;
const HOST = process.env.HOST || '0.0.0.0';

app.listen(PORT, HOST, () => {
  console.log(`Secure API Gateway running on ${HOST}:${PORT}`);
  console.log('Environment: ' + (process.env.NODE_ENV || 'development'));
});

module.exports = app;